interceptor.preaction:


						String beginTime = rrequest.getStringAttribute("MEASURE_DT", "");// 取出输入的查询时间

						//从明细返回的日期
						String MEASURE_DT_DTL = (String)rrequest.getRequest().getSession().getAttribute("MEASURE_DT_DTL");

						//System.out.println("MEASURE_DT:" + MEASURE_DT);

						if (beginTime.equals("")) 
						{
							//将明细返回的日期赋给当前日期
							if(MEASURE_DT_DTL!=null && !MEASURE_DT_DTL.equals("")){
								rrequest.setAttribute("MEASURE_DT", MEASURE_DT_DTL);
							}else{
								Connection conn = rrequest.getConnection();
								PreparedStatement pstmt = null;
								try {
										String SQL = "Select DATA_DT from IBS.T8_DATA_DT";
										pstmt = conn.prepareStatement(SQL);
										ResultSet resultSet = pstmt.executeQuery();
										while (resultSet.next()) {
						                     String date=resultSet.getString("DATA_DT");
						                     rrequest.setAttribute("MEASURE_DT", date);
					                    }

										resultSet.close();
										pstmt.close();
									} 
								catch (Exception e) {
										e.printStackTrace();
								}
							}
                        }

